<template>
	<header
		class="sticky top-0 z-10 flex items-center justify-between border-b bg-surface-white px-3 py-2.5 sm:px-5"
	>
		<Breadcrumbs :items="breadcrumbs" />
	</header>
<div class="md:w-3/4 md:mx-auto py-5 mx-5">
		<div class="grid grid-cols-3 gap-5 mb-5">
			<Link
				doctype="Discussion Activity"
				v-model="discussionID"
				:placeholder="__('Discussion')"
			/>
			<Link doctype="User" v-model="member" :placeholder="__('Student')" />
			<FormControl
				v-model="status"
				type="select"
				:options="statusOptions"
				:placeholder="__('Status')"
			/>
		</div>
		<ListView
			v-if="submissions.loading || submissions.data?.length"
			:columns="submissionColumns"
			:rows="submissions.data"
			rowKey="name"
		>
			<ListHeader
				class="mb-2 grid items-center space-x-4 rounded bg-surface-gray-2 p-2"
			>
				<ListHeaderItem :item="item" v-for="item in submissionColumns" />
			</ListHeader>
			<ListRows>
				<router-link
					v-for="row in submissions.data"
					:to="{
						name: 'DiscussionActivitySubmission',
						params: {
							discussionID: row.disc_activity,
							submissionName: row.name,
						},
					}"
				>
					<ListRow :row="row">
						<template #default="{ column, item }">
							<ListRowItem :item="row[column.key]" :align="column.align">
								<div v-if="column.key == 'status'">
									<Badge :theme="getStatusTheme(row[column.key])">
										{{ row[column.key] }}
									</Badge>
								</div>
								<div v-else>
									{{ row[column.key] }}
								</div>
							</ListRowItem>
						</template>
					</ListRow>
				</router-link>
			</ListRows>
		</ListView>
		<div
			v-else
			class="text-center p-5 text-ink-gray-5 mt-52 w-3/4 md:w-1/2 mx-auto space-y-2"
		>
			<Pencil class="size-8 mx-auto stroke-1 text-ink-gray-4" />
			<div class="text-xl font-medium">
				{{ __('No submissions') }}
			</div>
			<div class="leading-5">
				{{ __('There are no submissions for this discussion activity.') }}
			</div>
		</div>
	</div>
</template>
<script setup>
import {
	Badge,
	createListResource,
	Breadcrumbs,
	FormControl,
	ListView,
	ListHeader,
	ListHeaderItem,
	ListRows,
	ListRow,
	ListRowItem,
} from 'frappe-ui'
import { computed, onMounted, inject, watch, ref } from 'vue'
import { useRouter } from 'vue-router'
import { Pencil } from 'lucide-vue-next'
import Link from '@/components/Controls/Link.vue'

const router = useRouter()
const user = inject('$user')
const dayjs = inject('$dayjs')
const discussionID = ref('')
const member = ref('')
const status = ref('')

onMounted(() => {
	if (!user.data?.is_instructor && !user.data?.is_moderator) {
		router.push({ name: 'Courses' })
	}
	discussionID.value = router.currentRoute.value.query.discussionID
	member.value = router.currentRoute.value.query.member
	status.value = router.currentRoute.value.query.status
	reloadSubmissions()
})


const getDiscussionFilters = () => {
	let filters = {}
	if (discussionID.value) {
		filters.disc_activity = discussionID.value
	}
	if (member.value) {
		filters.member = member.value
	}
	if (status.value) {
		filters.status = status.value
	}
	return filters
}

const submissions = createListResource({
	doctype: 'Discussion Submission',
	fields: ['name', 'disc_activity', 'member','student_name', 'score', 'percentage', 'disc_title', 'status', 'extra_credit', 'fudge_points' ],
	orderBy: 'creation desc',
	transform(data) {
		return data.map((row) => {
			return {
				...row,
				creation: dayjs(row.creation).fromNow(),
			}
		})
	},
})

// watch changes in discussionID, member, and status and if changes in any then reload submissions. Also update the url query params for the same
watch([discussionID, member, status], () => {
	router.push({
		query: {
			discussionID: discussionID.value,
			member: member.value,
			status: status.value,
		},
	})
	reloadSubmissions()
})

const reloadSubmissions = () => {
	submissions.update({
		filters: getDiscussionFilters(),
	})
	submissions.reload()
}

const discussionColumns = computed(() => {
	return [
		{
			label: __('Student'),
			key: 'student_name',
			width: 1,
		},
		{
			label: __('Discussion Title'),
			key: 'disc_title',
			width: 2,
		},
			{
			label: __('Submitted'),
			key: 'creation',
			width: 1,
			align: 'left',
		},
		{
			label: __('Status'),
			key: 'status',
			width: 1,
			align: 'center',
		},
		{
			label: __('Score'),
			key: 'score',
			width: 1,
			align: 'center',
		},

	]
})

const statusOptions = computed(() => {
	return [
		{ label: '', value: '' },
		{ label: __('Pass'), value: 'Pass' },
		{ label: __('Fail'), value: 'Fail' },
		{ label: __('Not Graded'), value: 'Not Graded' },
		{ label: __('Graded'), value: 'Graded' },
	]
})

const getStatusTheme = (status) => {
	if (status === 'Pass' || status === 'Graded') {
		return 'green'
	} else if (status === 'Not Graded') {
		return 'blue'
	} else {
		return 'red'
	}
}

const breadcrumbs = computed(() => {
	return [{ label: __('Discussion Submissions') }]
})
</script>
